const input = $input.first().json;
const action = input.action || 'list_products';

const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const pgHeaders = { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY };

const allCreds = await helpers.httpRequest({
  method: 'GET',
  url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.shopify&select=cred_key,cred_value',
  headers: pgHeaders
});
const creds = {};
for (const c of (allCreds || [])) creds[c.cred_key] = c.cred_value;

if (!creds.shopify_store || !creds.shopify_access_token) {
  return [{ json: { error: 'Shopify credentials missing. Use add_credential to set shopify_store and shopify_access_token.' } }];
}

const store = creds.shopify_store.replace(/^https?:\/\//, '').replace(/\/+$/, '');
const gqlUrl = 'https://' + store + '/admin/api/2026-01/graphql.json';
const gqlHeaders = {
  'X-Shopify-Access-Token': creds.shopify_access_token,
  'Content-Type': 'application/json'
};

async function gql(query, variables) {
  const res = await helpers.httpRequest({
    method: 'POST',
    url: gqlUrl,
    headers: gqlHeaders,
    body: JSON.stringify({ query: query, variables: variables || {} }),
    json: true
  });
  if (res.errors) {
    const msg = res.errors.map(function(e){ return e.message || JSON.stringify(e); }).join('; ');
    throw new Error(msg);
  }
  return res.data;
}

function truncate(s, n) {
  if (!s) return '';
  s = String(s);
  return s.length > n ? s.substring(0, n) + '...' : s;
}

function money(m) {
  if (!m) return '';
  if (typeof m === 'object') return (m.amount || '') + ' ' + (m.currencyCode || '');
  return String(m);
}

function parseTags(v) {
  if (v === undefined || v === null || v === '') return undefined;
  if (Array.isArray(v)) return v.map(String);
  return String(v).split(',').map(function(s){ return s.trim(); }).filter(Boolean);
}

function gidOrNum(v, type) {
  if (!v) return v;
  const s = String(v);
  if (s.indexOf('gid://') === 0) return s;
  return 'gid://shopify/' + type + '/' + s;
}


// ─────────────────────────────── list_products ───────────────────────────────
if (action === 'list_products') {
  const first = Math.min(parseInt(input.limit) || 20, 100);
  const query = 'query LP($first: Int!, $after: String, $query: String) { products(first: $first, after: $after, query: $query) { edges { cursor node { id title handle status vendor productType tags variants(first: 1) { edges { node { price } } } } } pageInfo { hasNextPage endCursor } } }';
  try {
    const data = await gql(query, { first: first, after: input.cursor || null, query: input.search || null });
    const edges = data.products.edges;
    if (edges.length === 0) return [{ json: { result: 'No products found.' } }];
    let result = 'Found ' + edges.length + ' products:\n\n';
    for (const e of edges) {
      const p = e.node;
      const price = p.variants.edges[0] ? p.variants.edges[0].node.price : '';
      result += 'ID ' + p.id + '\n  "' + p.title + '" [' + p.status + ']';
      if (price) result += ' — ' + price;
      if (p.vendor) result += ' (' + p.vendor + ')';
      result += '\n';
    }
    if (data.products.pageInfo.hasNextPage) result += '\n(more available — next cursor: ' + data.products.pageInfo.endCursor + ')';
    return [{ json: { result: result.trim() } }];
  } catch (err) {
    return [{ json: { error: 'Failed to list products: ' + err.message } }];
  }

// ─────────────────────────────── get_product ───────────────────────────────
} else if (action === 'get_product') {
  if (!input.id) return [{ json: { error: 'Parameter "id" is required (product numeric ID or gid://shopify/Product/...).' } }];
  const id = gidOrNum(input.id, 'Product');
  const query = 'query GP($id: ID!) { product(id: $id) { id title handle status description vendor productType tags createdAt updatedAt variants(first: 20) { edges { node { id title sku price inventoryQuantity inventoryItem { id } } } } featuredImage { url altText } } }';
  try {
    const data = await gql(query, { id: id });
    const p = data.product;
    if (!p) return [{ json: { error: 'Product not found: ' + id } }];
    let result = '**' + p.title + '**\n';
    result += 'ID: ' + p.id + '\n';
    result += 'Status: ' + p.status + ' | Handle: ' + p.handle + '\n';
    if (p.vendor) result += 'Vendor: ' + p.vendor + '\n';
    if (p.productType) result += 'Type: ' + p.productType + '\n';
    if (p.tags && p.tags.length) result += 'Tags: ' + p.tags.join(', ') + '\n';
    result += '\nVariants (' + p.variants.edges.length + '):\n';
    for (const ve of p.variants.edges) {
      const v = ve.node;
      result += '  ' + v.id + ' — "' + v.title + '" — ' + v.price;
      if (v.sku) result += ' (SKU: ' + v.sku + ')';
      if (v.inventoryQuantity !== null && v.inventoryQuantity !== undefined) result += ' [qty: ' + v.inventoryQuantity + ']';
      if (v.inventoryItem && v.inventoryItem.id) result += '\n    inventory_item_id: ' + v.inventoryItem.id;
      result += '\n';
    }
    if (p.description) result += '\nDescription:\n' + truncate(p.description, 1500) + '\n';
    if (result.length > 5000) result = result.substring(0, 5000) + '\n\n... (truncated)';
    return [{ json: { result: result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to get product: ' + err.message } }];
  }

// ─────────────────────────────── create_product ───────────────────────────────
} else if (action === 'create_product') {
  if (!input.title) return [{ json: { error: 'Parameter "title" is required.' } }];
  const productInput = { title: input.title };
  if (input.description) productInput.descriptionHtml = input.description;
  if (input.vendor) productInput.vendor = input.vendor;
  if (input.product_type) productInput.productType = input.product_type;
  if (input.status) productInput.status = String(input.status).toUpperCase();
  const tags = parseTags(input.tags);
  if (tags) productInput.tags = tags;

  const query = 'mutation CP($input: ProductInput!) { productCreate(input: $input) { product { id title handle status } userErrors { field message } } }';
  try {
    const data = await gql(query, { input: productInput });
    const r = data.productCreate;
    if (r.userErrors && r.userErrors.length) {
      return [{ json: { error: 'productCreate rejected: ' + r.userErrors.map(function(e){ return (e.field ? e.field.join('.') + ': ' : '') + e.message; }).join('; ') } }];
    }
    let result = 'Product created: ' + r.product.id + '\n  "' + r.product.title + '" [' + r.product.status + ']';
    if (input.price) {
      const pd = await gql('query V($id: ID!) { product(id: $id) { variants(first: 1) { edges { node { id } } } } }', { id: r.product.id });
      const variantId = pd.product.variants.edges[0] ? pd.product.variants.edges[0].node.id : null;
      if (variantId) {
        const priceMut = 'mutation SP($productId: ID!, $variants: [ProductVariantsBulkInput!]!) { productVariantsBulkUpdate(productId: $productId, variants: $variants) { productVariants { id price } userErrors { field message } } }';
        const pr = await gql(priceMut, { productId: r.product.id, variants: [{ id: variantId, price: String(input.price) }] });
        if (pr.productVariantsBulkUpdate.userErrors && pr.productVariantsBulkUpdate.userErrors.length === 0) {
          result += '\n  price: ' + input.price;
        }
      }
    }
    return [{ json: { result: result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to create product: ' + err.message } }];
  }

// ─────────────────────────────── update_product ───────────────────────────────
} else if (action === 'update_product') {
  if (!input.id) return [{ json: { error: 'Parameter "id" is required.' } }];
  const id = gidOrNum(input.id, 'Product');
  const productInput = { id: id };
  let hasProductChange = false;
  if (input.title !== undefined && input.title !== '') { productInput.title = input.title; hasProductChange = true; }
  if (input.description !== undefined && input.description !== '') { productInput.descriptionHtml = input.description; hasProductChange = true; }
  if (input.vendor !== undefined && input.vendor !== '') { productInput.vendor = input.vendor; hasProductChange = true; }
  if (input.product_type !== undefined && input.product_type !== '') { productInput.productType = input.product_type; hasProductChange = true; }
  if (input.status !== undefined && input.status !== '') { productInput.status = String(input.status).toUpperCase(); hasProductChange = true; }
  const tags = parseTags(input.tags);
  if (tags) { productInput.tags = tags; hasProductChange = true; }
  const hasPrice = input.price !== undefined && input.price !== '';
  if (!hasProductChange && !hasPrice) {
    return [{ json: { error: 'At least one field (title, description, vendor, product_type, status, tags, price) is required.' } }];
  }
  try {
    let result = '';
    if (hasProductChange) {
      const query = 'mutation UP($input: ProductInput!) { productUpdate(input: $input) { product { id title status } userErrors { field message } } }';
      const data = await gql(query, { input: productInput });
      const r = data.productUpdate;
      if (r.userErrors && r.userErrors.length) {
        return [{ json: { error: 'productUpdate rejected: ' + r.userErrors.map(function(e){ return e.message; }).join('; ') } }];
      }
      result = 'Product updated: ' + r.product.id + '\n  "' + r.product.title + '" [' + r.product.status + ']';
    }
    if (hasPrice) {
      const pd = await gql('query V($id: ID!) { product(id: $id) { variants(first: 1) { edges { node { id } } } } }', { id: id });
      const variantId = pd.product.variants.edges[0] ? pd.product.variants.edges[0].node.id : null;
      if (!variantId) {
        result += (result ? '\n' : '') + 'Price not updated: no variant found.';
      } else {
        const priceMut = 'mutation SP($productId: ID!, $variants: [ProductVariantsBulkInput!]!) { productVariantsBulkUpdate(productId: $productId, variants: $variants) { productVariants { id price } userErrors { field message } } }';
        const pr = await gql(priceMut, { productId: id, variants: [{ id: variantId, price: String(input.price) }] });
        if (pr.productVariantsBulkUpdate.userErrors && pr.productVariantsBulkUpdate.userErrors.length) {
          result += (result ? '\n' : '') + 'Price update failed: ' + pr.productVariantsBulkUpdate.userErrors.map(function(e){ return e.message; }).join('; ');
        } else {
          result += (result ? '\n' : '') + '  price: ' + input.price;
        }
      }
    }
    return [{ json: { result: result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to update product: ' + err.message } }];
  }

// ─────────────────────────────── delete_product ───────────────────────────────
} else if (action === 'delete_product') {
  if (!input.id) return [{ json: { error: 'Parameter "id" is required.' } }];
  const id = gidOrNum(input.id, 'Product');
  const query = 'mutation DP($input: ProductDeleteInput!) { productDelete(input: $input) { deletedProductId userErrors { field message } } }';
  try {
    const data = await gql(query, { input: { id: id } });
    const r = data.productDelete;
    if (r.userErrors && r.userErrors.length) {
      return [{ json: { error: 'productDelete rejected: ' + r.userErrors.map(function(e){ return e.message; }).join('; ') } }];
    }
    return [{ json: { result: 'Product deleted: ' + r.deletedProductId } }];
  } catch (err) {
    return [{ json: { error: 'Failed to delete product: ' + err.message } }];
  }

// ─────────────────────────────── list_orders ───────────────────────────────
} else if (action === 'list_orders') {
  const first = Math.min(parseInt(input.limit) || 20, 100);
  const query = 'query LO($first: Int!, $after: String, $query: String) { orders(first: $first, after: $after, query: $query, sortKey: CREATED_AT, reverse: true) { edges { cursor node { id name createdAt displayFinancialStatus displayFulfillmentStatus totalPriceSet { shopMoney { amount currencyCode } } customer { firstName lastName email } tags } } pageInfo { hasNextPage endCursor } } }';
  try {
    const data = await gql(query, { first: first, after: input.cursor || null, query: input.search || null });
    const edges = data.orders.edges;
    if (edges.length === 0) return [{ json: { result: 'No orders found.' } }];
    let result = 'Found ' + edges.length + ' orders:\n\n';
    for (const e of edges) {
      const o = e.node;
      const total = money(o.totalPriceSet && o.totalPriceSet.shopMoney);
      const cust = o.customer ? ((o.customer.firstName || '') + ' ' + (o.customer.lastName || '')).trim() : '';
      result += o.name + ' — ' + total + ' [' + o.displayFinancialStatus + '/' + o.displayFulfillmentStatus + ']';
      if (cust) result += ' — ' + cust;
      result += '\n  ' + o.id;
      if (o.tags && o.tags.length) result += ' — tags: ' + o.tags.join(', ');
      result += '\n';
    }
    if (data.orders.pageInfo.hasNextPage) result += '\n(more available — next cursor: ' + data.orders.pageInfo.endCursor + ')';
    return [{ json: { result: result.trim() } }];
  } catch (err) {
    return [{ json: { error: 'Failed to list orders: ' + err.message } }];
  }

// ─────────────────────────────── get_order ───────────────────────────────
} else if (action === 'get_order') {
  if (!input.id) return [{ json: { error: 'Parameter "id" is required (order numeric ID or gid).' } }];
  const id = gidOrNum(input.id, 'Order');
  const query = 'query GO($id: ID!) { order(id: $id) { id name createdAt note tags displayFinancialStatus displayFulfillmentStatus totalPriceSet { shopMoney { amount currencyCode } } subtotalPriceSet { shopMoney { amount currencyCode } } customer { id firstName lastName email phone } shippingAddress { address1 city zip country } lineItems(first: 50) { edges { node { id title quantity sku variant { id price } } } } fulfillmentOrders(first: 10) { edges { node { id status } } } } }';
  try {
    const data = await gql(query, { id: id });
    const o = data.order;
    if (!o) return [{ json: { error: 'Order not found: ' + id } }];
    let result = '**Order ' + o.name + '**\n';
    result += 'ID: ' + o.id + '\n';
    result += 'Created: ' + o.createdAt + '\n';
    result += 'Status: ' + o.displayFinancialStatus + ' / ' + o.displayFulfillmentStatus + '\n';
    result += 'Total: ' + money(o.totalPriceSet && o.totalPriceSet.shopMoney) + ' (subtotal ' + money(o.subtotalPriceSet && o.subtotalPriceSet.shopMoney) + ')\n';
    if (o.tags && o.tags.length) result += 'Tags: ' + o.tags.join(', ') + '\n';
    if (o.note) result += 'Note: ' + o.note + '\n';
    if (o.customer) {
      const name = ((o.customer.firstName || '') + ' ' + (o.customer.lastName || '')).trim();
      result += '\nCustomer: ' + name + ' <' + (o.customer.email || '') + '>\n';
    }
    if (o.shippingAddress) {
      result += 'Ship to: ' + (o.shippingAddress.address1 || '') + ', ' + (o.shippingAddress.zip || '') + ' ' + (o.shippingAddress.city || '') + ', ' + (o.shippingAddress.country || '') + '\n';
    }
    result += '\nLine items:\n';
    for (const le of o.lineItems.edges) {
      const li = le.node;
      result += '  ' + li.quantity + 'x "' + li.title + '"';
      if (li.variant && li.variant.price) result += ' @ ' + li.variant.price;
      result += '\n    line_item_id: ' + li.id + '\n';
    }
    if (o.fulfillmentOrders && o.fulfillmentOrders.edges.length) {
      result += '\nFulfillment orders:\n';
      for (const fe of o.fulfillmentOrders.edges) result += '  ' + fe.node.id + ' [' + fe.node.status + ']\n';
    }
    if (result.length > 5000) result = result.substring(0, 5000) + '\n\n... (truncated)';
    return [{ json: { result: result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to get order: ' + err.message } }];
  }

// ─────────────────────────────── update_order ───────────────────────────────
} else if (action === 'update_order') {
  if (!input.id) return [{ json: { error: 'Parameter "id" is required.' } }];
  const id = gidOrNum(input.id, 'Order');
  const orderInput = { id: id };
  let has = false;
  const tags = parseTags(input.tags);
  if (tags) { orderInput.tags = tags; has = true; }
  if (input.note !== undefined && input.note !== '') { orderInput.note = input.note; has = true; }
  if (!has) return [{ json: { error: 'At least one of "tags" or "note" is required.' } }];
  const query = 'mutation UO($input: OrderInput!) { orderUpdate(input: $input) { order { id name tags note } userErrors { field message } } }';
  try {
    const data = await gql(query, { input: orderInput });
    const r = data.orderUpdate;
    if (r.userErrors && r.userErrors.length) {
      return [{ json: { error: 'orderUpdate rejected: ' + r.userErrors.map(function(e){ return e.message; }).join('; ') } }];
    }
    let result = 'Order updated: ' + r.order.name + ' (' + r.order.id + ')';
    if (r.order.tags && r.order.tags.length) result += '\n  tags: ' + r.order.tags.join(', ');
    if (r.order.note) result += '\n  note: ' + truncate(r.order.note, 200);
    return [{ json: { result: result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to update order: ' + err.message } }];
  }

// ─────────────────────────────── edit_order_quantity ───────────────────────────────
} else if (action === 'edit_order_quantity') {
  if (!input.id) return [{ json: { error: 'Parameter "id" (order ID) is required.' } }];
  if (!input.line_item_id) return [{ json: { error: 'Parameter "line_item_id" is required (get it from get_order output).' } }];
  if (input.quantity === undefined || input.quantity === '') return [{ json: { error: 'Parameter "quantity" is required (new quantity, integer).' } }];
  const qty = parseInt(input.quantity);
  if (isNaN(qty) || qty < 0) return [{ json: { error: 'Parameter "quantity" must be a non-negative integer.' } }];
  const id = gidOrNum(input.id, 'Order');
  const origLineId = gidOrNum(input.line_item_id, 'LineItem');
  try {
    const begin = await gql('mutation B($id: ID!) { orderEditBegin(id: $id) { calculatedOrder { id } userErrors { field message } } }', { id: id });
    if (begin.orderEditBegin.userErrors && begin.orderEditBegin.userErrors.length) {
      return [{ json: { error: 'orderEditBegin failed: ' + begin.orderEditBegin.userErrors.map(function(e){ return e.message; }).join('; ') } }];
    }
    const calcId = begin.orderEditBegin.calculatedOrder.id;
    const origNum = origLineId.replace('gid://shopify/LineItem/', '');
    const calc = await gql('query C($id: ID!) { calculatedOrder(id: $id) { lineItems(first: 100) { edges { node { id quantity title } } } } }', { id: calcId });
    const targetLine = (calc.calculatedOrder.lineItems.edges || []).find(function(e){ return e.node.id.indexOf(origNum) !== -1; });
    if (!targetLine) {
      return [{ json: { error: 'Line item ' + origLineId + ' not found in calculated order. Run get_order again to verify the line_item_id.' } }];
    }
    const setQty = await gql('mutation SQ($id: ID!, $lineItemId: ID!, $quantity: Int!) { orderEditSetQuantity(id: $id, lineItemId: $lineItemId, quantity: $quantity) { calculatedOrder { id } userErrors { field message } } }', { id: calcId, lineItemId: targetLine.node.id, quantity: qty });
    if (setQty.orderEditSetQuantity.userErrors && setQty.orderEditSetQuantity.userErrors.length) {
      return [{ json: { error: 'orderEditSetQuantity failed: ' + setQty.orderEditSetQuantity.userErrors.map(function(e){ return e.message; }).join('; ') } }];
    }
    const commit = await gql('mutation CM($id: ID!) { orderEditCommit(id: $id, notifyCustomer: false, staffNote: "Edited via n8n-claw") { order { id name } userErrors { field message } } }', { id: calcId });
    if (commit.orderEditCommit.userErrors && commit.orderEditCommit.userErrors.length) {
      return [{ json: { error: 'orderEditCommit failed: ' + commit.orderEditCommit.userErrors.map(function(e){ return e.message; }).join('; ') } }];
    }
    return [{ json: { result: 'Order ' + commit.orderEditCommit.order.name + ' edited: line item quantity set to ' + qty } }];
  } catch (err) {
    return [{ json: { error: 'Failed to edit order: ' + err.message } }];
  }

// ─────────────────────────────── create_fulfillment ───────────────────────────────
} else if (action === 'create_fulfillment') {
  if (!input.order_id) return [{ json: { error: 'Parameter "order_id" is required.' } }];
  const orderId = gidOrNum(input.order_id, 'Order');
  try {
    const q = await gql('query FO($id: ID!) { order(id: $id) { fulfillmentOrders(first: 10) { edges { node { id status } } } } }', { id: orderId });
    const fos = (q.order && q.order.fulfillmentOrders && q.order.fulfillmentOrders.edges) || [];
    const openFos = fos.filter(function(e){ return e.node.status === 'OPEN' || e.node.status === 'IN_PROGRESS'; });
    if (openFos.length === 0) {
      return [{ json: { error: 'No open fulfillment orders found for ' + orderId + '. Order may already be fully fulfilled.' } }];
    }
    const lineItemsByFO = openFos.map(function(e){ return { fulfillmentOrderId: e.node.id }; });
    const fulfillment = {
      lineItemsByFulfillmentOrder: lineItemsByFO,
      notifyCustomer: input.notify_customer === true || input.notify_customer === 'true'
    };
    if (input.tracking_number || input.tracking_company || input.tracking_url) {
      fulfillment.trackingInfo = {};
      if (input.tracking_number) fulfillment.trackingInfo.number = input.tracking_number;
      if (input.tracking_company) fulfillment.trackingInfo.company = input.tracking_company;
      if (input.tracking_url) fulfillment.trackingInfo.url = input.tracking_url;
    }
    const mut = 'mutation F($fulfillment: FulfillmentV2Input!) { fulfillmentCreate(fulfillment: $fulfillment) { fulfillment { id status trackingInfo { number company url } } userErrors { field message } } }';
    const data = await gql(mut, { fulfillment: fulfillment });
    const r = data.fulfillmentCreate;
    if (r.userErrors && r.userErrors.length) {
      return [{ json: { error: 'fulfillmentCreate failed: ' + r.userErrors.map(function(e){ return e.message; }).join('; ') } }];
    }
    let result = 'Fulfillment created: ' + r.fulfillment.id + ' [' + r.fulfillment.status + ']';
    if (r.fulfillment.trackingInfo && r.fulfillment.trackingInfo.length) {
      const ti = r.fulfillment.trackingInfo[0];
      result += '\nTracking: ' + (ti.company || '') + ' ' + (ti.number || '') + (ti.url ? ' (' + ti.url + ')' : '');
    }
    return [{ json: { result: result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to create fulfillment: ' + err.message } }];
  }

// ─────────────────────────────── list_customers ───────────────────────────────
} else if (action === 'list_customers') {
  const first = Math.min(parseInt(input.limit) || 20, 100);
  const query = 'query LC($first: Int!, $after: String, $query: String) { customers(first: $first, after: $after, query: $query) { edges { cursor node { id firstName lastName email phone tags numberOfOrders amountSpent { amount currencyCode } } } pageInfo { hasNextPage endCursor } } }';
  try {
    const data = await gql(query, { first: first, after: input.cursor || null, query: input.search || null });
    const edges = data.customers.edges;
    if (edges.length === 0) return [{ json: { result: 'No customers found.' } }];
    let result = 'Found ' + edges.length + ' customers:\n\n';
    for (const e of edges) {
      const c = e.node;
      const name = ((c.firstName || '') + ' ' + (c.lastName || '')).trim() || '(no name)';
      result += name + ' <' + (c.email || 'no email') + '>\n';
      result += '  ' + c.id;
      if (c.numberOfOrders) result += ' — ' + c.numberOfOrders + ' orders';
      if (c.amountSpent) result += ' (' + money(c.amountSpent) + ')';
      if (c.tags && c.tags.length) result += ' — tags: ' + c.tags.join(', ');
      result += '\n';
    }
    if (data.customers.pageInfo.hasNextPage) result += '\n(more available — next cursor: ' + data.customers.pageInfo.endCursor + ')';
    return [{ json: { result: result.trim() } }];
  } catch (err) {
    return [{ json: { error: 'Failed to list customers: ' + err.message } }];
  }

// ─────────────────────────────── create_customer ───────────────────────────────
} else if (action === 'create_customer') {
  if (!input.email && !input.phone) return [{ json: { error: 'At least one of "email" or "phone" is required.' } }];
  const customerInput = {};
  if (input.email) customerInput.email = input.email;
  if (input.phone) customerInput.phone = input.phone;
  if (input.first_name) customerInput.firstName = input.first_name;
  if (input.last_name) customerInput.lastName = input.last_name;
  if (input.note) customerInput.note = input.note;
  const tags = parseTags(input.tags);
  if (tags) customerInput.tags = tags;
  const query = 'mutation CC($input: CustomerInput!) { customerCreate(input: $input) { customer { id firstName lastName email } userErrors { field message } } }';
  try {
    const data = await gql(query, { input: customerInput });
    const r = data.customerCreate;
    if (r.userErrors && r.userErrors.length) {
      return [{ json: { error: 'customerCreate failed: ' + r.userErrors.map(function(e){ return e.message; }).join('; ') } }];
    }
    const c = r.customer;
    const name = ((c.firstName || '') + ' ' + (c.lastName || '')).trim() || '(no name)';
    return [{ json: { result: 'Customer created: ' + c.id + '\n  ' + name + ' <' + (c.email || '') + '>' } }];
  } catch (err) {
    return [{ json: { error: 'Failed to create customer: ' + err.message } }];
  }

// ─────────────────────────────── update_customer ───────────────────────────────
} else if (action === 'update_customer') {
  if (!input.id) return [{ json: { error: 'Parameter "id" is required.' } }];
  const id = gidOrNum(input.id, 'Customer');
  const customerInput = { id: id };
  let has = false;
  if (input.email !== undefined && input.email !== '') { customerInput.email = input.email; has = true; }
  if (input.phone !== undefined && input.phone !== '') { customerInput.phone = input.phone; has = true; }
  if (input.first_name !== undefined && input.first_name !== '') { customerInput.firstName = input.first_name; has = true; }
  if (input.last_name !== undefined && input.last_name !== '') { customerInput.lastName = input.last_name; has = true; }
  if (input.note !== undefined && input.note !== '') { customerInput.note = input.note; has = true; }
  const tags = parseTags(input.tags);
  if (tags) { customerInput.tags = tags; has = true; }
  if (!has) return [{ json: { error: 'At least one field (email, phone, first_name, last_name, note, tags) is required.' } }];
  const query = 'mutation UC($input: CustomerInput!) { customerUpdate(input: $input) { customer { id firstName lastName email tags } userErrors { field message } } }';
  try {
    const data = await gql(query, { input: customerInput });
    const r = data.customerUpdate;
    if (r.userErrors && r.userErrors.length) {
      return [{ json: { error: 'customerUpdate failed: ' + r.userErrors.map(function(e){ return e.message; }).join('; ') } }];
    }
    const c = r.customer;
    const name = ((c.firstName || '') + ' ' + (c.lastName || '')).trim();
    let result = 'Customer updated: ' + c.id;
    if (name) result += '\n  ' + name;
    if (c.email) result += ' <' + c.email + '>';
    if (c.tags && c.tags.length) result += '\n  tags: ' + c.tags.join(', ');
    return [{ json: { result: result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to update customer: ' + err.message } }];
  }

// ─────────────────────────────── adjust_inventory ───────────────────────────────
} else if (action === 'adjust_inventory') {
  if (!input.inventory_item_id) return [{ json: { error: 'Parameter "inventory_item_id" is required (get it from get_product output — each variant has inventory_item_id).' } }];
  if (input.delta === undefined || input.delta === '') return [{ json: { error: 'Parameter "delta" is required (positive or negative integer, e.g. 10 or -5).' } }];
  const delta = parseInt(input.delta);
  if (isNaN(delta)) return [{ json: { error: 'Parameter "delta" must be an integer.' } }];
  const inventoryItemId = gidOrNum(input.inventory_item_id, 'InventoryItem');
  let locationId = input.location_id ? gidOrNum(input.location_id, 'Location') : null;
  try {
    if (!locationId) {
      const locs = await gql('query L { locations(first: 5, includeInactive: false) { edges { node { id name } } } }', {});
      const active = (locs.locations.edges || []).map(function(e){ return e.node; });
      if (active.length === 0) return [{ json: { error: 'No active locations found. Set location_id explicitly.' } }];
      if (active.length > 1) {
        return [{ json: { error: 'Multiple locations exist — pass location_id explicitly. Available: ' + active.map(function(l){ return l.id + ' (' + l.name + ')'; }).join(', ') } }];
      }
      locationId = active[0].id;
    }
    const mut = 'mutation Adj($input: InventoryAdjustQuantitiesInput!) { inventoryAdjustQuantities(input: $input) { inventoryAdjustmentGroup { createdAt reason } userErrors { field message } } }';
    const vars = {
      input: {
        reason: 'correction',
        name: 'available',
        changes: [{ delta: delta, inventoryItemId: inventoryItemId, locationId: locationId }]
      }
    };
    const data = await gql(mut, vars);
    const r = data.inventoryAdjustQuantities;
    if (r.userErrors && r.userErrors.length) {
      return [{ json: { error: 'inventoryAdjustQuantities failed: ' + r.userErrors.map(function(e){ return e.message; }).join('; ') } }];
    }
    return [{ json: { result: 'Inventory adjusted by ' + (delta >= 0 ? '+' : '') + delta + ' for ' + inventoryItemId + ' at ' + locationId } }];
  } catch (err) {
    return [{ json: { error: 'Failed to adjust inventory: ' + err.message } }];
  }

} else {
  return [{ json: { error: 'Unknown action: "' + action + '". Available: list_products, get_product, create_product, update_product, delete_product, list_orders, get_order, update_order, edit_order_quantity, create_fulfillment, list_customers, create_customer, update_customer, adjust_inventory.' } }];
}
